import React from "react";
import { Link } from "react-router-dom";
import "./LandingPage.css";

const features = [
  {
    title: "Role-Based Dashboards",
    description:
      "Operators, admins, teachers, students, and regulators each get dedicated workflows.",
  },
  {
    title: "Academic Operations",
    description:
      "Manage classes, courses, materials, assignments, exams, and attendance in one system.",
  },
  {
    title: "Compliance and Audit",
    description:
      "Track school compliance, review rules, and keep education governance transparent.",
  },
];

export default function LandingPage() {
  return (
    <main className="landing-page" aria-label="EduLink landing page">
      <section className="landing-hero">
        <p className="landing-badge">Edulink Platform</p>
        <h1>One platform for schools, teaching, compliance, and student success.</h1>
        <p className="landing-subtitle">
          EduLink connects your education ecosystem with secure role-based access,
          operational dashboards, and end-to-end workflows.
        </p>
        <div className="landing-actions">
          <Link className="landing-btn landing-btn-primary" to="/login">
            Sign In
          </Link>
          <a className="landing-btn landing-btn-secondary" href="#features">
            Explore Features
          </a>
        </div>
      </section>

      <section id="features" className="landing-features" aria-label="Platform features">
        {features.map((feature) => (
          <article key={feature.title} className="landing-feature-card">
            <h2>{feature.title}</h2>
            <p>{feature.description}</p>
          </article>
        ))}
      </section>
    </main>
  );
}

